-- ============================================
-- Legislacao full-site: alan-rick / Senado / projetos_lei
-- Seed completo do recorte: autoria parlamentar substantiva Senado 2023-2026
-- ============================================
-- Fonte oficial: Senado Federal Dados Abertos
--   https://legis.senado.leg.br/dadosabertos/senador/5672/autorias.json
--   https://legis.senado.leg.br/dadosabertos/materia/{codigo}.json
--   https://legis.senado.leg.br/dadosabertos/materia/autoria/{codigo}.json
--   https://www25.senado.leg.br/web/atividade/materias/-/materia/{codigo}
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = alan-rick-senado-completo-autoria-substantiva-2023-2026-20260505
--   coverage_scope = inventario_completo_senado_autoria_substantiva_2023_2026_20260505
--
-- Filtro factual: endpoint senador/5672/autorias.json com
--   IndicadorAutorPrincipal=Sim, siglas substantivas em
--   (PLS, PL, PEC, PLP, PRS, PDL, PDS, PCE), e endpoint
--   materia/autoria/{codigo}.json confirmando CodigoParlamentar=5672
--   com NumOrdemAutor=1. Resultado deste snapshot: 34 rows.
--
-- O recorte e completo apenas para a autoria parlamentar substantiva no Senado
-- retornada pelo endpoint oficial. Nao e inventario completo da vida publica do
-- candidato.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO escreve em historico_politico.
-- Esta migration NAO popula tema, destaque, destaque_motivo nem situacao
--   (campos editoriais/curatoriais, fora do contrato bruto de ingest oficial).
-- Esta migration NAO promove UI/whitelist publica; isso exige novo fechamento.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  projetos_total int;
  target_present int;
  target_count int;
  target_with_other_coverage int;
  mandato_senado_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'alan-rick';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'alan-rick: candidato ausente neste banco local/CI minimo; seed projetos_lei Senado pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO projetos_total
  FROM projetos_lei
  WHERE candidato_id = cand_id;

  SELECT count(*) INTO target_count
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND coverage_id = 'alan-rick-senado-completo-autoria-substantiva-2023-2026-20260505';

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('156810', '157013', '158017', '158780', '159521', '159878', '159879', '160000', '160747', '161241', '161729', '155971', '156267', '162125', '162801', '162821', '163137', '163986', '164424', '166406', '162676', '167202', '167327', '167636', '167880', '168082', '168193', '168700', '169476', '169603', '170072', '172048', '173802', '173681');

  IF target_present NOT IN (0, 34) THEN
    RAISE EXCEPTION 'Pre-condicao alan-rick: overlap parcial com rows alvo Senado em projetos_lei: % de 34', target_present;
  END IF;

  IF target_present = 34 AND target_count <> 34 THEN
    RAISE EXCEPTION 'Pre-condicao alan-rick: 34 rows alvo ja existem, mas apenas % com coverage_id alvo', target_count;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('156810', '157013', '158017', '158780', '159521', '159878', '159879', '160000', '160747', '161241', '161729', '155971', '156267', '162125', '162801', '162821', '163137', '163986', '164424', '166406', '162676', '167202', '167327', '167636', '167880', '168082', '168193', '168700', '169476', '169603', '170072', '172048', '173802', '173681')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'alan-rick-senado-completo-autoria-substantiva-2023-2026-20260505';

  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao alan-rick: % rows alvo Senado ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO mandato_senado_count
  FROM historico_politico hp
  WHERE hp.candidato_id = cand_id
    AND COALESCE(hp.tipo_evento, 'mandato') = 'mandato'
    AND (hp.cargo ILIKE '%Senador%' OR hp.cargo_canonico = 'Senador')
    AND UPPER(COALESCE(hp.estado, '')) = 'AC'
    AND COALESCE(hp.periodo_inicio, 9999) <= 2026
    AND COALESCE(hp.periodo_fim, 9999) >= 2023;

  IF mandato_senado_count < 1 THEN
    RAISE EXCEPTION 'Pre-condicao alan-rick: mandato Senado/AC 2023-2026 nao encontrado em historico_politico';
  END IF;
END $$;

